def suma(a, b):
    return a + b

if __name__ == '__main__':
    try:
        resultado = suma(2, 3)
        if resultado == 5:
            print('CRITERIO OK')
        else:
            print(f'CRITERIO FALLO: suma(2,3) devolvió {resultado} en lugar de 5')
    except Exception as e:
        print(f'CRITERIO FALLO: {e}')

def resta(a, b):
    return a - b

if __name__ == '__main__':
    try:
        resultado = resta(5, 3)
        if resultado == 2:
            print('CRITERIO OK')
        else:
            print(f'CRITERIO FALLO: resta(5,3) devolvió {resultado}, se esperaba 2')
    except Exception as e:
        print(f'CRITERIO FALLO: {e}')

